# -*- coding: utf-8 -*-
"""aplicar_desvios2.py — convierte la seccion Desvios de FAMILIA a PRODUCTO (rotulo oficial).
Idempotente. Corre: python app_carga/aplicar_desvios2.py  (desde worms_supabase o app_carga)."""
import os, re, io, sys, base64

HERE=os.path.dirname(os.path.abspath(__file__))
def _find(b):
    for c in (b, os.path.join(b,"app_carga")):
        if os.path.exists(os.path.join(c,"planificacion.py")): return c
    return None
APP=_find(HERE) or _find(os.getcwd())
if not APP: print("ERROR: no encuentro planificacion.py"); sys.exit(1)
pp=os.path.join(APP,"planificacion.py")
s=io.open(pp,encoding="utf-8").read()
if "v_desvio_stock_producto" in s:
    print("planificacion.py: YA a nivel producto -> sin cambios"); sys.exit(0)
NEWF=base64.b64decode("").decode("utf-8")
pat=re.compile(r"def _desvio_stock_ledger\(USR, cat, conectar\):.*?(?=\n\ndef _reconciliacion_semanal\(USR, cat, conectar\):)", re.S)
if not pat.search(s):
    print("ERROR: no encontre la funcion _desvio_stock_ledger. AVISAR."); sys.exit(1)
s2=pat.sub(lambda m: NEWF, s, count=1)
io.open(pp,"w",encoding="utf-8",newline="\n").write(s2)
import py_compile
py_compile.compile(pp,doraise=True)
print("OK -> planificacion.py ahora a nivel producto (v_desvio_stock_producto). Compila.")
print("Ahora: git add app_carga/planificacion.py && git commit -m 'Desvios por producto' && git push")
